mapper.select:
SELECT t.*
FROM eb_program_task t

	t.deleted_at IS NULL
	AND t.program_id = #{query.programId}

		AND t.program_id IN
		#{sp}

	AND t.version_id = #{query.versionId}
	AND t.status = #{query.status}
	AND t.priority = #{query.priority}
	AND t.pid = #{query.pid}
	AND t.uid = #{query.uid}

		AND t.name LIKE CONCAT('%', #{query.nameLike}, '%')


		AND t.uid IN
		#{a}


		AND t.id IN (
			SELECT m.task_id FROM eb_program_task_member m
			WHERE m.deleted_at IS NULL AND m.uid IN
			#{mu}
		)




				AND (
					t.program_id IN (
						SELECT p.id FROM eb_program p WHERE p.deleted_at IS NULL
						AND (p.uid = #{query.adminUid} OR p.creator_uid = #{query.adminUid})
					)
					OR t.uid = #{query.adminUid}
					OR t.creator_uid = #{query.adminUid}
					OR t.id IN (
						SELECT tm.task_id FROM eb_program_task_member tm
						WHERE tm.deleted_at IS NULL AND tm.uid = #{query.adminUid}
					)
				)

			AND t.uid = #{query.adminUid}

				AND (
					t.uid = #{query.adminUid}

						OR t.id IN
						#{tid}

				)

			AND t.creator_uid = #{query.adminUid}
			AND t.uid = #{query.adminUid}



ORDER BY t.sort ASC, t.id ASC
